+
+interface AgentRunResult {
+  content: string;
+  isError: boolean;
+}
+
+interface DelegationInput {
+  agent_id: string;
+  instructions: string;
+}
+
+const EMPTY_DELEGATION_RESULT = "Delegated agent completed without producing text.";
+
+function isDelegationInput(input: unknown): input is DelegationInput {
+  if (!input || typeof input !== "object") return false;
+
+  const { agent_id, instructions } = input as Record<string, unknown>;
+  return typeof agent_id === "string" && typeof instructions === "string";
+}
+
+function createToolResult(
+  toolUseId: string,
+  content: string,
+  isError: boolean
+): string {
+  return JSON.stringify({
+    type: "tool_result",
+    is_error: isError,
+    content,
+    tool_use_id: toolUseId,
+  });
+}
+
+function createDelegateToolUse(
+  toolUseId: string,
+  input: unknown
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        content: [{
+          type: "tool_use",
+          id: toolUseId,
+          name: "delegate_task",
+          input,
+        }],
+      },
+    },
+  };
+}
+
+function createToolResultResponse(
+  toolUseId: string,
+  content: string,
+  isError: boolean
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "user",
+      message: {
+        content: [{
+          type: "tool_result",
+          tool_use_id: toolUseId,
+          is_error: isError,
+          content,
+        }],
+      },
+    },
+  };
+}
+
+function isDelegationProtocolResponse(response: StreamResponse): boolean {
+  if (response.type === "error") return true;
+  if (response.type !== "claude_json" || !response.data || typeof response.data !== "object") {
+    return false;
+  }
+
+  const data = response.data as { type?: string; message?: { content?: unknown } };
+  return data.type === "user" ||
+    (data.type === "assistant" && Array.isArray(data.message?.content));
+}
