import { Context } from "hono";
import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";
import { globalImageHandler } from "../utils/imageHandling.ts";
import type { 
  ProviderChatRequest, 
  ProviderResponse, 
  ChatRoomMessage,
  AgentCommand 
} from "../providers/types.ts";

interface AgentRunResult {
  content: string;
  isError: boolean;
}

interface DelegationInput {
  agent_id: string;
  instructions: string;
}

const EMPTY_DELEGATION_RESULT = "Delegated agent completed without producing text.";

function isDelegationInput(input: unknown): input is DelegationInput {
  if (!input || typeof input !== "object") return false;

  const { agent_id, instructions } = input as Record<string, unknown>;
  return typeof agent_id === "string" && typeof instructions === "string";
}

function createToolResult(
  toolUseId: string,
  content: string,
  isError: boolean
): string {
  return JSON.stringify({
    type: "tool_result",
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  });
}

function createDelegateToolUse(
  toolUseId: string,
  input: unknown
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "assistant",
      message: {
        content: [{
          type: "tool_use",
          id: toolUseId,
          name: "delegate_task",
          input,
        }],
      },
    },
  };
}

function createToolResultResponse(
  toolUseId: string,
  content: string,
  isError: boolean
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        content: [{
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: isError,
          content,
        }],
      },
    },
  };
}

function isDelegationProtocolResponse(response: StreamResponse): boolean {
  if (response.type === "error") return true;
  if (response.type !== "claude_json" || !response.data || typeof response.data !== "object") {
    return false;
  }

  const data = response.data as { type?: string; message?: { content?: unknown } };
  return data.type === "user" ||
    (data.type === "assistant" && Array.isArray(data.message?.content));
}

/**
 * Parse structured commands from chat messages
 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;
}

/**
 * Execute multi-agent chat with provider abstraction
 */
async function* executeMultiAgentChat(
  request: ChatRequest,
  requestAbortControllers: Map<string, AbortController>,
  debugMode: boolean = false
): AsyncGenerator<StreamResponse> {
  try {
    // Create abort controller
    const abortController = new AbortController();
    requestAbortControllers.set(request.requestId, abortController);

    if (debugMode) {
      console.debug("[Multi-Agent] Processing request:", {
        message: request.message.substring(0, 100) + "...",
        availableAgents: request.availableAgents?.map(a => a.id),
      });
    }

    // Parse agent mentions and commands
    const mentionMatches = request.message.match(/@([\w-]+)/g);
    const command = parseAgentCommand(request.message);

    if (mentionMatches && mentionMatches.length === 1) {
      // Single agent mention - direct execution
      const mentionedAgentId = mentionMatches[0].substring(1);

